import React, { useMemo } from 'react';

import './budgetView.scss';

import { BudgetItemDTO } from 'Repositories/budgets/dtos/BudgetItemDTO';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';
import PlusSvg from 'Components/svg/PlusSvg';
import AuButton from 'Components/form/button/AuButton';
import { UuidT } from 'Shared/types/UuidT';
import { sidebarService } from 'Services/sidebarService';
import { SidebarNameE } from 'Components/sidebar/SidebarNameE';
import { useLoadBudgetGroups } from 'Repositories/budgets/useLoadBudgetGroups';
import { useLoadBudgetItems } from 'Repositories/budgets/useLoadBudgetItems';

import BudgetGroup from '../group/BudgetGroup';
import CreateGroupSidebar from '../group/sidebars/CreateGroupSidebar';
import CreateBudgetItemSidebar from '../item/sidebars/CreateBudgetItemSidebar';
import EditGroupSidebar from '../group/sidebars/edit/EditGroupSidebar';
import DeleteGroupSidebar from '../group/sidebars/DeleteGroupSidebar';
import EditBudgetItemSidebar from '../item/sidebars/EditBudgetItemSidebar';
import DeleteBudgetItemSidebar from '../item/sidebars/DeleteBudgetItemSidebar';

type BudgetItemsByGroupsT = {
  [key: UuidT]: BudgetItemDTO[];
};

type PropsT = {
  budgetId: UuidT;
};

const BudgetView = ({ budgetId }: PropsT) => {
  const { budgetGroups } = useLoadBudgetGroups(budgetId);
  const { budgetItems } = useLoadBudgetItems(budgetId);

  const budgetItemsByGroups: BudgetItemsByGroupsT = useMemo(
    () =>
      budgetGroups?.reduce((result, current) => {
        return {
          ...result,
          [current.id]: budgetItems.filter(
            item => item.budgetGroupId === current.id,
          ),
        };
      }, {}),
    [budgetGroups, budgetItems],
  );

  return (
    <div className="budget">
      {budgetGroups.map(budgetGroup => (
        <BudgetGroup
          budgetGroup={budgetGroup}
          budgetItems={budgetItemsByGroups[budgetGroup.id]}
          key={budgetGroup.id}
        />
      ))}

      <div className="budget-action">
        <AuButton
          kind={AuButtonKindE.SECONDARY}
          onClick={() => {
            sidebarService.openFirst(SidebarNameE.CREATE_BUDGET_GROUP, {
              budgetId,
            });
          }}
          size={AuButtonSizeE.MEDIUM}
        >
          <PlusSvg />
          Add group
        </AuButton>
      </div>

      <CreateGroupSidebar />
      <EditGroupSidebar />
      <DeleteGroupSidebar />

      <CreateBudgetItemSidebar />
      <EditBudgetItemSidebar />
      <DeleteBudgetItemSidebar />
    </div>
  );
};

export default BudgetView;

