import React from 'react';
import classNames from 'classnames';

import './budgetItem.scss';

import { BudgetItemDTO } from 'Repositories/budgets/dtos/BudgetItemDTO';
import { priceFormat } from 'Shared/utils/currencyHelper';
import CategoryBadge from 'Components/categoryBage/CategoryBadge';
import { CategoryTypeE } from 'Shared/types/CategoryTypeE';
import { sidebarService } from 'Services/sidebarService';
import { SidebarNameE } from 'Components/sidebar/SidebarNameE';
import PencilSvg from 'Components/svg/PencilSvg';
import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';

import BudgetItemCell from '../group/cell/BudgetItemCell';

type PropsT = {
  budgetItem: BudgetItemDTO;
};

const BudgetItem = ({ budgetItem }: PropsT) => {
  return (
    <div className="budget-item">
      <div className="budget-item__description">
        <AuButton
          kind={AuButtonKindE.ICON}
          size={AuButtonSizeE.SMALL}
          className="budget-item__edit-button"
          onClick={() => {
            sidebarService.open(SidebarNameE.EDIT_BUDGET_ITEM, {
              budgetItem,
            });
          }}
        >
          <PencilSvg />
        </AuButton>

        <div className="budget-item__name">{budgetItem.name}</div>

        <CategoryBadge
          category="Restaurants"
          categoryType={budgetItem.type}
        />
      </div>

      <BudgetItemCell
        label="Planned"
        value={priceFormat(budgetItem.plannedAmount, 0)}
      />

      {budgetItem.type === CategoryTypeE.INCOME ? (
        <BudgetItemCell
          className={classNames({
            'color--secondary':
              budgetItem.actualAmount >= budgetItem.plannedAmount,
            'color--red': budgetItem.actualAmount < budgetItem.plannedAmount,
          })}
          label="Gained"
          value={priceFormat(budgetItem.actualAmount, 0)}
        />
      ) : (
        <BudgetItemCell
          className={classNames({
            'color--secondary':
              budgetItem.actualAmount <= budgetItem.plannedAmount,
            'color--red': budgetItem.actualAmount > budgetItem.plannedAmount,
          })}
          label="Spend"
          value={priceFormat(budgetItem.actualAmount, 0)}
        />
      )}

      {budgetItem.type === CategoryTypeE.INCOME ? (
        <BudgetItemCell
          className={classNames({
            'color--secondary': budgetItem.remainingAmount <= 0,
            'color--red': budgetItem.remainingAmount > 0,
          })}
          label="To go"
          value={priceFormat(budgetItem.remainingAmount, 0)}
        />
      ) : (
        <BudgetItemCell
          className={classNames({
            'color--secondary': budgetItem.remainingAmount >= 0,
            'color--red': budgetItem.remainingAmount < 0,
          })}
          label="Remaining"
          value={priceFormat(budgetItem.remainingAmount, 0)}
        />
      )}
    </div>
  );
};

export default BudgetItem;

