import React from 'react';
import classNames from 'classnames';

import './auButton.scss';

import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import { AuButtonSizeE } from 'Components/form/button/AuButtonSizeE';

type PropsT = {
  areaPressed?: boolean;
  className?: string;
  children: React.ReactNode;
  form?: string;
  kind?: AuButtonKindE;
  onClick?: () => void;
  size?: AuButtonSizeE;
  testId?: string;
  type?: 'submit' | 'reset' | 'button';
  disabled?: boolean;
};

const AuButton = ({
  areaPressed = false,
  className,
  children,
  form,
  kind = AuButtonKindE.PRIMARY,
  onClick,
  size,
  testId,
  type = 'button',
  disabled = false,
}: PropsT) => (
  <button
    aria-pressed={areaPressed}
    className={classNames(`au-button au-button--${kind}`, className, {
      [`au-button--${size}`]: size,
    })}
    disabled={disabled}
    data-testid={testId}
    form={form}
    onClick={
      onClick
        ? e => {
            e.preventDefault();

            onClick();
          }
        : undefined
    }
    type={type}
  >
    {children}
  </button>
);

export default AuButton;

