  margin: 8px;
  font-weight: 600;
}

.budget-side-box {
  padding: 16px 22px 1px 20px;
  border-radius: 20px;
  box-shadow: 0 0 0 1px var(--color-gray-3) inset;
}

.budget-side-box__head {
  margin-block-end: 2px;
  font-size: 12px;
  font-weight: 600;
}

.budget-side-cells {
  display: flex;
  gap: 20px;
  margin-block-end: 20px;

  .budget-item-cell {
    align-items: flex-start;
  }

  @media (width < 60rem) {
    .budget-item-cell {
      padding-left: 0;
    }
  }
}

