import React from 'react';

import './budgetsPage.scss';

import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import PlusSvg from 'Components/svg/PlusSvg';
import MainLayout from 'Components/layouts/main/MainLayout';
import PageHeader from 'Components/pageHeader/PageHeader';
import { sidebarService } from 'Services/sidebarService';
import { SidebarNameE } from 'Components/sidebar/SidebarNameE';
import { useLoadBudgets } from 'Repositories/budgets/useLoadBudgets';
import Spinner from 'Components/spinner/Spinner';

import CreateBudgetSidebar from './sidebars/create/CreateBudgetSidebar';
import BudgetPreview from './preview/BudgetPreview';
import EditBudgetSidebar from './sidebars/edit/EditBudgetSidebar';
import DeleteBudgetSidebar from './sidebars/delete/DeleteBudgetSidebar';

const BudgetsPage = () => {
  const { loading, budgets } = useLoadBudgets();

  if (loading) {
    return (
      <MainLayout className="budgets-page">
        <Spinner />
      </MainLayout>
    );
  }

  return (
    <MainLayout className="budgets-page">
      <div className="main-content">
        <PageHeader title="My budgets">
          <AuButton
            kind={AuButtonKindE.LINK}
            onClick={() => {
              sidebarService.openFirst(SidebarNameE.CREATE_BUDGET);
            }}
          >
            <PlusSvg />
            Add budget
          </AuButton>
        </PageHeader>

        {/* Block for feature filters */}
        {/*<div className="budgets-page__actions">*/}
        {/*  <div className="budgets-page__filters">*/}
        {/*    <div className="chips">*/}
        {/*      <div className="chips-list">*/}
        {/*        <AuButton*/}
        {/*          areaPressed*/}
        {/*          kind={AuButtonKindE.CHIPS}*/}
        {/*          onClick={console.log}*/}
        {/*        >*/}
        {/*          My budgets*/}
        {/*        </AuButton>*/}

        {/*        <AuButton*/}
        {/*          kind={AuButtonKindE.CHIPS}*/}
        {/*          onClick={console.log}*/}
        {/*        >*/}
        {/*          Shared with me*/}
        {/*        </AuButton>*/}
        {/*      </div>*/}
        {/*    </div>*/}
        {/*  </div>*/}

        {/*  <div className="budgets-page__side" />*/}
        {/*</div>*/}

        <div className="budgets-list">
          {budgets.map(budget => (
            <BudgetPreview
