import { useCallback } from 'react';

import { useEventListener } from 'Shared/hooks/useEventListener';
import useToggle from 'Shared/hooks/useToggle';

export const useOutsideClickListener = (
  element: HTMLElement | null,
  fn: (event: Event) => void,
) => {
  const { on: mouseDownOutside, toggleOff, toggleOn } = useToggle(false);

  const handleMouseDown = useCallback(
    (event: Event) => {
      const isTargetElement = element?.contains(event.target as Node);

      if (!element || isTargetElement) {
        return;
      }

      toggleOn();
    },
    [element, toggleOn],
  );

  const handleMouseUp = useCallback(
    (event: Event) => {
      const isTargetElement = element?.contains(event.target as Node);

      if (!element || isTargetElement || !mouseDownOutside) {
        return;
      }

      toggleOff();
      fn(event);
    },
    [element, fn, mouseDownOutside, toggleOff],
  );

  useEventListener('mousedown', handleMouseDown);
  useEventListener('mouseup', handleMouseUp);
};

