export const useEventListener = (
  eventType: string,
  func: (evt: Event) => void,
  throttleDuration?: number,
) => {
  useEffect(() => {
    const listenedFunction = throttleDuration
      ? throttle(func, throttleDuration)
      : func;

    document.addEventListener(eventType, listenedFunction);

    return () => {
      document.removeEventListener(eventType, listenedFunction);
    };
  }, [eventType, func, throttleDuration]);
};

