import { useEffect, useRef } from 'react';

import useToggle from 'Shared/hooks/useToggle';
import { useOutsideClickListener } from 'Shared/hooks/useOutsideClickListener';
import useChanged from 'Shared/hooks/useChanged';

export const useIsDropdownOpen = <V>(value: V[], multiple: boolean) => {
  const containerRef = useRef(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const {
    on: isDropdownOpen,
    toggleOn: onShowDropdown,
    toggleOff: onHideDropdown,
    onToggle: onToggleDropdown,
  } = useToggle(false);

  useOutsideClickListener(
    isDropdownOpen ? containerRef.current : null,
    onHideDropdown,
  );

  useEffect(() => {
    const input = inputRef.current;

    const onFocus = (event: FocusEvent) => {
      if (!isDropdownOpen && input && event.target === input) {
        onShowDropdown();

        input.setSelectionRange(input.value.length, input.value.length);
      }
    };

    const onBlur = (event: FocusEvent) => {
      if (isDropdownOpen && input && event.target === input) {
        onHideDropdown();
      }
    };

    input?.addEventListener('focusin', onFocus);
    input?.addEventListener('focusout', onBlur);

    return () => {
      input?.removeEventListener('focusin', onFocus);
      input?.removeEventListener('focusout', onBlur);
    };
  }, [isDropdownOpen, onHideDropdown, onShowDropdown]);

  useEffect(() => {
    const input = inputRef.current;

    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Enter' && input === event.target) {
        event.preventDefault();

        onToggleDropdown();
      }
    };

    input?.addEventListener('keydown', onKeyDown);

    return () => {
      input?.removeEventListener('keydown', onKeyDown);
    };
  }, [onToggleDropdown]);

  const valueChanged = useChanged(JSON.stringify(value));

  useEffect(() => {
    if (!multiple && valueChanged) {
      onHideDropdown();
    }
  }, [multiple, onHideDropdown, valueChanged]);

  useEffect(() => {
    const input = inputRef.current;

    input?.addEventListener('click', onToggleDropdown);

    return () => {
      input?.removeEventListener('click', onToggleDropdown);
    };
  }, [onToggleDropdown]);

  return {
    containerRef,
    inputRef,
    isDropdownOpen,
  };
};

