import React, { ReactNode, useEffect, useRef } from 'react';

import './modal.css';

import { useGlobalValue } from 'Shared/store/useGlobalValue';
import { GlobalStoreFieldE } from 'Shared/types/GlobalStoreFieldE';
import { useDidMount } from 'Shared/hooks/useDidMount';
import { modalService } from 'Services/modalService';
import useChanged from 'Shared/hooks/useChanged';

import { ModalTypeE } from './ModalTypeE';
import { ModalNameE } from './ModalNameE';
import { useOutsideClickListener } from 'Shared/hooks/useOutsideClickListener';
import classNames from 'classnames';

type PropsT = {
  children: ReactNode;
  name: ModalNameE;
  title: string;
  type?: ModalTypeE;
};

const Modal = ({
  children,
  name,
  title,
  type = ModalTypeE.REGULAR,
}: PropsT) => {
  const dialogRef = useRef<HTMLDialogElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  const modals = useGlobalValue(GlobalStoreFieldE.MODALS);

  const currentModal = modals.find(modal => modal.name === name);
  const currentModalChanged = useChanged(currentModal);

  useDidMount(() => {
    modalService.close(name);
  });

  useEffect(() => {
    if (!currentModalChanged) {
      return;
    }

    if (currentModal) {
      dialogRef.current?.showModal();
    } else {
      dialogRef.current?.close();
    }
  }, [currentModal, currentModalChanged]);

  useOutsideClickListener(currentModal ? contentRef.current : null, () =>
    modalService.close(name),
  );

  return (
    <dialog
      className={classNames('modal-content', `modal--${type}`)}
      ref={dialogRef}
    >
      <div
        onClick={e => e.stopPropagation()}
        ref={contentRef}
      >
        {title && <h2>{title}</h2>}

        {children}
      </div>
    </dialog>
  );
};

export default Modal;

