import React, { useState } from 'react';

import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import PlusSvg from 'Components/svg/PlusSvg';
import AuDropdown, {
  AuDropdownItemT,
} from 'Components/form/dropdown/AuDropdown';
import useToggle from 'Shared/hooks/useToggle';

type PropsT = {
  actions: AuDropdownItemT[];
  label?: string;
};

const ActionDropdown = ({ actions, label = 'Actions' }: PropsT) => {
  const { on: isOpen, onToggle, toggleOff } = useToggle(false);

  return (
    <AuDropdown
      items={actions}
      isOpen={isOpen}
      onClose={toggleOff}
    >
      <AuButton
        kind={AuButtonKindE.LINK}
        onClick={onToggle}
      >
        <PlusSvg />
        {label}
      </AuButton>
    </AuDropdown>
  );
};

export default ActionDropdown;

