import React, { useRef, useEffect } from 'react';

import './auDropdown.scss';

import { AuDropdownItemT } from 'Components/form/dropdown/AuDropdownItemT';

type PropsT = {
  items: AuDropdownItemT[];
  isOpen: boolean;
  onClose: () => void;
  children: React.ReactNode;
};

const AuDropdown = ({ items, isOpen, onClose, children }: PropsT) => {
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node)
      ) {
        onClose();
      }
    };

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [isOpen, onClose]);

  const handleItemClick = (item: AuDropdownItemT) => {
    item.onClick();
    onClose();
  };

  return (
    <div
      className="au-dropdown"
      ref={dropdownRef}
    >
      {children}

      {isOpen && (
        <div className="au-dropdown__menu">
          {items.map((item, index) => (
            <button
              key={index}
              className="au-dropdown__item"
              onClick={() => handleItemClick(item)}
              type="button"
            >
              {item.icon && (
                <span className="au-dropdown__icon">{item.icon}</span>
              )}
              {item.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default AuDropdown;

