import React from 'react';

import './bankAccountsPage.scss';

import AuButton from 'Components/form/button/AuButton';
import { AuButtonKindE } from 'Components/form/button/AuButtonKindE';
import SidebarLayout from 'Components/sidebar/SidebarLayout';
import PageHeader from 'Components/pageHeader/PageHeader';

import BankAccountsList from './list/BankAccountsList';
import AccountFormSidebar from './form/AccountFormSidebar';
import AccountInfoSidebar from './form/AccountInfoSidebar';
import DeleteAccountSidebar from './form/DeleteAccountSidebar';
import PlaidLink from './plaid/PlaidLink';

import { sidebarService } from 'Services/sidebarService';
import { SidebarNameE } from 'Components/sidebar/SidebarNameE';
import { useQueryClient } from '@tanstack/react-query';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';

const BankAccountsPage = () => {
  const queryClient = useQueryClient();
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const handleAccountCreated = () => {
    queryClient.invalidateQueries({ queryKey: [ApiGatewayE.BANK_ACCOUNTS] });
  };

  return (
    <SidebarLayout className="bank-accounts-page">
      <PageHeader title="My bank accounts">
        <div className="bank-accounts-page__last-sync">
          <nav className="dropdown">
            <div className="dropdown-toggle">+ Actions</div>
            <ul className="dropdown-menu">
              <li>
                <AuButton
                  kind={AuButtonKindE.LINK}
                  onClick={() => sidebarService.open(SidebarNameE.ACCOUNT, {})}
                >
                  Add Manual Account
                </AuButton>
              </li>
              <li>
                <AuButton
                  kind={AuButtonKindE.LINK}
                  onClick={() => console.log('Need implement sync data')}
                >
                  Sync data (<span>Last sync on Mar 12 </span>)
                </AuButton>
              </li>
              <li>
                <PlaidLink />
              </li>
            </ul>
          </nav>
        </div>
      </PageHeader>

      <BankAccountsList />

      <AccountFormSidebar />
      <AccountInfoSidebar />
      <DeleteAccountSidebar />
    </SidebarLayout>
  );
};

export default BankAccountsPage;

