import { memo, useEffect } from 'react';
import { usePlaidLink } from 'react-plaid-link';

import { useSetPlaidAccessToken } from './useSetPlaidAccessToken';

type PropsT = {
  onClose: () => void;
  linkToken: string;
};

const PlaidOpenButton = ({ onClose, linkToken }: PropsT) => {
  const onSetPlaidAccessToken = useSetPlaidAccessToken();

  const config: Parameters<typeof usePlaidLink>[0] = {
    token: linkToken,
    onSuccess: async (public_token, metadata) => {
      const response = await onSetPlaidAccessToken(public_token);
      console.log('metadata', metadata);
      console.log('response', response);

      onClose();
    },
    onExit: (error, metadata) => {
      console.log('User exited Plaid Link', error, metadata);

      onClose();
    },
  };

  const { open, ready } = usePlaidLink(config);

  useEffect(() => {
    if (ready) {
      open();
    }
  }, [open, ready]);

  return null;
};

export default memo(PlaidOpenButton);

