import { usePlaidLink } from './plaid/usePlaidLink';

import { sidebarService } from 'Services/sidebarService';
import { SidebarNameE } from 'Components/sidebar/SidebarNameE';
import { useQueryClient } from '@tanstack/react-query';
import { ApiGatewayE } from 'Shared/types/api/ApiGatewayE';

const BankAccountsPage = () => {
  const queryClient = useQueryClient();
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const handleAccountCreated = () => {
    queryClient.invalidateQueries({ queryKey: [ApiGatewayE.BANK_ACCOUNTS] });
  };

  const { handleClick } = usePlaidLink();

  return (
    <SidebarLayout>
      <PageHeader title="My bank accounts">
        <ActionDropdown
          label="Actions"
          actions={[
            {
              label: 'Add Manual Account',
              onClick: () => sidebarService.open(SidebarNameE.ACCOUNT, {}),
            },
            {
              label: 'Sync data (Last sync on Mar 12)',
              onClick: () => console.log('Need implement sync data'),
            },
            {
              label: 'Connect to your Bank',
              onClick: handleClick,
            },
          ]}
        />
      </PageHeader>

      <BankAccountsList />

      <AccountFormSidebar />
      <AccountInfoSidebar />
      <DeleteAccountSidebar />

      {linkToken && opened && (
        <PlaidOpenButton
          linkToken={linkToken}
          onClose={onClose}
        />
      )}
    </SidebarLayout>
  );
};

export default BankAccountsPage;

