import { useCallback, useEffect } from 'react';
import { usePlaidLink as usePlaidLinkSDK } from 'react-plaid-link';

import useAsyncFn from 'Shared/hooks/useAsyncFn';
import useToggle from 'Shared/hooks/useToggle';
import { notificationService } from 'Services/notificationService';

import { useGenerateToken } from './useGenerateToken';
import { useSetPlaidAccessToken } from './useSetPlaidAccessToken';

export const usePlaidLink = () => {
  const { on: shouldOpen, toggleOn: onShouldOpen, toggleOff: onClose } =
    useToggle(false);

  const generateToken = useGenerateToken();
  const setPlaidAccessToken = useSetPlaidAccessToken();

  const onGenerateToken = useCallback(async () => {
    return generateToken();
  }, [generateToken]);

  const {
    callAsyncFn: onGenerateClick,
    response: { data, error, loading },
    resetResponse,
  } = useAsyncFn(onGenerateToken);

  useEffect(() => {
    if (error) {
      notificationService.addAlert((error as Error).message);

      resetResponse();
      onClose();
    }
  }, [error, onClose, resetResponse]);

  const config: Parameters<typeof usePlaidLinkSDK>[0] = {
    token: data?.link_token || null,
    onSuccess: async (public_token, metadata) => {
      try {
        const response = await setPlaidAccessToken(public_token);
        console.log('metadata', metadata);
        console.log('response', response);
      } catch (error) {
        notificationService.addAlert((error as Error).message);
      } finally {
        onClose();
      }
    },
    onExit: (error, metadata) => {
      console.log('User exited Plaid Link', error, metadata);
      onClose();
    },
  };

  const { open, ready } = usePlaidLinkSDK(config);

  useEffect(() => {
    if (ready && shouldOpen && data?.link_token) {
      open();
    }
  }, [open, ready, shouldOpen, data?.link_token]);

  const handleClick = useCallback(async () => {
    if (data?.link_token && ready) {
      onShouldOpen();
      open();
    } else {
      await onGenerateClick();
      onShouldOpen();
    }
  }, [data?.link_token, ready, onGenerateClick, onShouldOpen, open]);

  return {
    handleClick,
    loading,
  };
};

