     1→import { NextFunction, Request } from 'express';
     2→import {
     3→  PaginatedResponse,
     4→  PaginateMiddleware,
     5→  QueryFilter,
     6→  RequestFilter,
     7→} from '../types/paginateTypes';
     8→import { convertRequestFilterToPrismaQuery } from '../utils/convertRequestFilterToPrismaQuery';
     9→
    10→const DEFAULT_PAGE = 1;
    11→const DEFAULT_PAGE_SIZE = parseInt(process.env.PAGE_SIZE || '20');
    12→
    13→// eslint-disable-next-line @typescript-eslint/no-unsafe-function-type
    14→const paginate = <TModel extends { count: Function; findMany: Function }>(
    15→  model: TModel,
    16→  queryFilters: (string | QueryFilter)[] = [],
    17→  requestFilters: (string | RequestFilter)[] = [],
    18→  include = {},
    19→  defaultOrderBy = { createdAt: 'desc' },
    20→  queryFilterOverride = {},
    21→): ReturnType<PaginateMiddleware<TModel>> => {
    22→  return async (req: Request, res: PaginatedResponse, next: NextFunction) => {
    23→    const { startDate, endDate } = req.query;
    24→
    25→    const filters = convertRequestFilterToPrismaQuery(
    26→      req,
    27→      queryFilters,
    28→      requestFilters,
    29→      queryFilterOverride,
    30→    );
    31→
    32→    if (startDate) {
    33→      filters.createdAt = {
    34→        ...(filters.createdAt as object),
    35→        gte: new Date(startDate as string),
    36→      };
    37→    }
    38→
    39→    if (endDate) {
    40→      filters.createdAt = {
    41→        ...(filters.createdAt as object),
    42→        lte: new Date(endDate as string),
    43→      };
    44→    }
    45→
    46→    const where = { ...filters };
    47→
    48→    const categoriesParam = (req.query as any).categories;
    49→    if (categoriesParam && categoriesParam.in) {
    50→      const raw = categoriesParam.in as string | string[];
    51→
    52→      const values = Array.isArray(raw)
    53→        ? raw
    54→        : (raw as string).split(',').filter(Boolean);
    55→
    56→      if (values.length > 0) {
    57→        where.categories = {
    58→          some: {
    59→            userAccountCategoryId: {
    60→              in: values,
    61→            },
    62→          },
    63→        };
    64→      }
    65→    }
    66→
    67→    const rawSearch = (req.query.searchTerm as string | undefined)?.trim();
    68→
    69→    if (rawSearch) {
    70→      const or: any[] = [
    71→        {
    72→          name: {
    73→            contains: rawSearch,
    74→            mode: 'insensitive',
    75→          },
    76→        },
    77→        {
    78→          merchantName: {
    79→            contains: rawSearch,
    80→            mode: 'insensitive',
    81→          },
    82→        },
    83→      ];
    84→
    85→      const numericAmount = Number(rawSearch);
    86→      if (!Number.isNaN(numericAmount)) {
    87→        or.push({
    88→          amount: {
    89→            equals: numericAmount,
    90→          },
    91→        });
    92→      }
    93→
    94→      where.OR = or;
    95→    }
    96→
    97→    const sortParam = (
    98→      req.query.sortOrder as string | undefined
    99→    )?.toLowerCase();
   100→    const sortOrder: 'asc' | 'desc' =
   101→      sortParam === 'asc' || sortParam === 'desc' ? sortParam : 'desc';
   102→
   103→    let orderBy: any = defaultOrderBy;
   104→
   105→    if (Array.isArray(defaultOrderBy)) {
   106→      orderBy = defaultOrderBy.map(ob => {
   107→        if (!ob || typeof ob !== 'object') return ob;
   108→        const field = Object.keys(ob)[0];
   109→        return { [field]: sortOrder };
   110→      });
   111→    } else if (defaultOrderBy && typeof defaultOrderBy === 'object') {
   112→      const fields = Object.keys(defaultOrderBy);
   113→      orderBy = fields.reduce((acc: any, field) => {
   114→        acc[field] = sortOrder;
   115→        return acc;
   116→      }, {});
   117→    }
   118→
   119→    const page = parseInt(req.query.page as string) || DEFAULT_PAGE;
   120→    const pageSize =
   121→      parseInt(req.query.pageSize as string) || DEFAULT_PAGE_SIZE;
   122→    const offset = (page - 1) * pageSize;
   123→
   124→    const totalCount = await model.count({ where });
   125→    const totalPages = Math.ceil(totalCount / pageSize);
   126→
   127→    const results = await model.findMany({
   128→      skip: offset,
   129→      take: pageSize,
   130→      where,
