import { NextFunction, Request } from 'express';
import {
  PaginatedResponse,
  PaginateMiddleware,
  QueryFilter,
  RequestFilter,
} from '../types/paginateTypes';
import { convertRequestFilterToPrismaQuery } from '../utils/convertRequestFilterToPrismaQuery';

const DEFAULT_PAGE = 1;
const DEFAULT_PAGE_SIZE = parseInt(process.env.PAGE_SIZE || '20');

// eslint-disable-next-line @typescript-eslint/no-unsafe-function-type
const paginate = <TModel extends { count: Function; findMany: Function }>(
  model: TModel,
  queryFilters: (string | QueryFilter)[] = [],
  requestFilters: (string | RequestFilter)[] = [],
  include = {},
  defaultOrderBy = { createdAt: 'desc' },
  queryFilterOverride = {},
): ReturnType<PaginateMiddleware<TModel>> => {
  return async (req: Request, res: PaginatedResponse, next: NextFunction) => {
    const { startDate, endDate } = req.query;

    const filters = convertRequestFilterToPrismaQuery(
      req,
      queryFilters,
      requestFilters,
      queryFilterOverride,
    );

    if (startDate) {
      filters.createdAt = {
        ...(filters.createdAt as object),
        gte: new Date(startDate as string),
      };
    }

    if (endDate) {
      filters.createdAt = {
        ...(filters.createdAt as object),
        lte: new Date(endDate as string),
      };
    }

    const where = { ...filters };

    const categoriesParam = (req.query as any).categories;
    if (categoriesParam && categoriesParam.in) {
      const raw = categoriesParam.in as string | string[];

      const values = Array.isArray(raw)
        ? raw
        : (raw as string).split(',').filter(Boolean);

      if (values.length > 0) {
        where.categories = {
          some: {
            userAccountCategoryId: {
              in: values,
            },
          },
        };
      }
    }

    const rawSearch = (req.query.searchTerm as string | undefined)?.trim();

    if (rawSearch) {
      const or: any[] = [
        {
          name: {
            contains: rawSearch,
            mode: 'insensitive',
          },
        },
        {
          merchantName: {
            contains: rawSearch,
            mode: 'insensitive',
          },
        },
      ];

      const numericAmount = Number(rawSearch);
      if (!Number.isNaN(numericAmount)) {
        or.push({
          amount: {
            equals: numericAmount,
          },
        });
      }

      where.OR = or;
    }

    const sortParam = (
      req.query.sortOrder as string | undefined
    )?.toLowerCase();
    const sortOrder: 'asc' | 'desc' =
      sortParam === 'asc' || sortParam === 'desc' ? sortParam : 'desc';

    let orderBy: any = defaultOrderBy;

    if (Array.isArray(defaultOrderBy)) {
      orderBy = defaultOrderBy.map(ob => {
        if (!ob || typeof ob !== 'object') return ob;
        const field = Object.keys(ob)[0];
        return { [field]: sortOrder };
      });
    } else if (defaultOrderBy && typeof defaultOrderBy === 'object') {
      const fields = Object.keys(defaultOrderBy);
      orderBy = fields.reduce((acc: any, field) => {
        acc[field] = sortOrder;
        return acc;
      }, {});
    }

    const page = parseInt(req.query.page as string) || DEFAULT_PAGE;
    const pageSize =
      parseInt(req.query.pageSize as string) || DEFAULT_PAGE_SIZE;
    const offset = (page - 1) * pageSize;

    const totalCount = await model.count({ where });
    const totalPages = Math.ceil(totalCount / pageSize);

    const results = await model.findMany({
      skip: offset,
      take: pageSize,
      where,
      orderBy,
      include,
    });

    res.paginatedData = {
      results,
      page,
      pageSize,
      totalCount,
      totalPages,
    };

    next();
  };
};

export default paginate;

