import { Prisma } from '@prisma/client';
import { Request, Response, NextFunction } from 'express';

// QueryFilter type to define supported query filter operations
export interface QueryFilter {
  [key: string]: 'contains' | 'equals' | 'gte' | 'lte' | 'in';
}

export interface RequestFilter {
  [key: string]: 'params';
}

export type QueryFilterType = (string | { [key: string]: string })[];

// PaginateMiddleware type with a generic model parameter to ensure Prisma compatibility
export type PaginateMiddleware<TModel> = (
  model: TModel,
  queryFilters?: (string | QueryFilter)[],
  requestFilters?: RequestFilter[],
  include?: Prisma.UserInclude, // Replace `UserInclude` with the correct model if needed
  orderBy?: Prisma.UserOrderByWithRelationInput, // Replace with the actual model’s order type
) => (req: Request, res: Response, next: NextFunction) => Promise<void>;

export interface PaginatedResponse extends Response {
  paginatedData?: {
    results: unknown[];
    page: number;
    pageSize: number;
    totalCount: number;
    totalPages: number;
  };
}

